#include <bits/stdc++.h>
using namespace std;
int n,m,a[102][102],s[102][102],ans;
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            scanf("%d",&a[i][j]);
            s[i][j]=(a[i][j]^1)+s[i-1][j]+s[i][j-1]-s[i-1][j-1];
        }
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)
            for(int k=min(i,j);k>ans;k--)
                if(s[i][j]-s[i-k][j]-s[i][j-k]+s[i-k][j-k]==0){
                    ans=max(ans,k);
                    break;
                }
    printf("%d",ans);
    return 0;
}
